# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json


class Inventory:
    def __init__(self):
        self.items = {}

    def add_item(self, item, owner):
        if item in self.items:
            self.items[item].append(owner)
        else:
            self.items[item] = [owner]

    def remove_item(self, item, owner):
        if item in self.items and owner in self.items[item]:
            self.items[item].remove(owner)


class Server:
    def __init__(self):
        self.inventory = Inventory()
        self.users = set()

    def state_event(self):
        return json.dumps({'type': 'inventory', 'content': self.inventory.items})

    async def notify_inventory(self):
        if self.users:  
            message = self.state_event()
            await asyncio.wait([user.send(message) for user in self.users])

    async def register(self, websocket):
        self.users.add(websocket)
        await self.notify_inventory()

    async def unregister(self, websocket):
        self.users.remove(websocket)
        await self.notify_inventory()

    async def transfer_item(self, item, from_user, to_user):
        self.inventory.remove_item(item, from_user)
        self.inventory.add_item(item, to_user)
        await self.notify_inventory()

    async def handle_message(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            if data['action'] == 'transfer':
                await self.transfer_item(data['item'], data['from'], data['to'])
            elif data['action'] == 'add':
                self.inventory.add_item(data['item'], data['owner'])
                await self.notify_inventory()
            elif data['action'] == 'remove':
                self.inventory.remove_item(data['item'], data['owner'])
                await self.notify_inventory()

    def serve(self):
        start_server = websockets.serve(self.handle_message, "localhost", 8765)
        asyncio.get_event_loop().run_until_complete(start_server)

if __name__ == "__main__":
    server = Server()
    server.serve()
    asyncio.get_event_loop().run_forever()